import React, { useState } from 'react';
import { BrowserRouter as Router, Routes, Route } from 'react-router-dom';
import { ThemeProvider } from "./context/ThemeContext";
import Navbar from './pages/Navbar';

function App() {
    return (
        <ThemeProvider>
            <Router>
                <Navbar />
                <Routes>
                    <Route path />
                </Routes>
            </Router>
        </ThemeProvider>
    );
}

export default App;
